// Build lookup map
stateCourtDirectories.forEach(sd => {
  sd.counties.forEach(c => {
    const key = `${c.state}-${c.county}`;
    countyCourtLookup[key] = c;
  });
});

// Helper to find county court info by state abbr and county name
// Supports partial and fuzzy matching (strips 'County', 'Parish', etc.)
export function findCountyCourtInfo(stateAbbr: string, countyName: string): CountyCourtInfo | undefined {
  const upper = stateAbbr.toUpperCase();

  // Try exact match first
  const exact = countyCourtLookup[`${upper}-${countyName}`];
  if (exact) return exact;

  // Try partial match
  const stateDir = stateCourtDirectories.find(sd => sd.stateAbbr === upper);
  if (!stateDir) return undefined;

  const normalized = countyName.toLowerCase()
    .replace(/\s+(county|parish|borough|census area|city|municipality)$/i, "")
    .trim();

  return stateDir.counties.find(c => {
    const cNorm = c.county.toLowerCase()
      .replace(/\s+(county|parish|borough|census area|city|municipality)$/i, "")
      .trim();
    return (
      cNorm === normalized ||
      cNorm.startsWith(normalized) ||
      normalized.startsWith(cNorm)
    );
  });
}

// Get all counties for a state
export function getStateCourtCounties(stateAbbr: string): CountyCourtInfo[] {
  const stateDir = stateCourtDirectories.find(sd => sd.stateAbbr === stateAbbr.toUpperCase());
  return stateDir?.counties || [];
}

// Get all state court directories
export function getAllStateCourtDirectories(): StateCourtDirectory[] {
  return stateCourtDirectories;
}
